SELECT * FROM status_change WHERE 1=1

    AND (student_no LIKE CONCAT('%', #{query.keyword}, '%')
         OR student_name LIKE CONCAT('%', #{query.keyword}, '%'))

AND student_id = #{query.studentId}
AND change_type = #{query.changeType}
AND status = #{query.status}
ORDER BY create_time DESC

SELECT * FROM status_change
WHERE student_id = #{studentId}
ORDER BY create_time DESC
